# solution.py
"""Team_Collaboration_Manager -- the collaboration engine.

This module powers the cooperative back end of the project: it tracks the
players (users), the shared sessions (projects), the coordinated work items
(tasks), the in-session communication (messages with attachments), the
performance dashboards (completion rate, timing, peer ratings) and the
exportable reports (CSV / PDF).

It is implemented as a single in-memory, thread-safe service object so that
many actors can connect to the same session concurrently. Standard library
only, ASCII only.
"""

import copy
import csv
import io
import threading
from collections import defaultdict
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import List, Optional

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role a user holds within the collaboration space."""

    MEMBER = "member"
    ADMIN = "admin"
    MANAGER = "manager"
    VIEWER = "viewer"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the manager can generate."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input data is malformed or violates an invariant."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor attempts an action they are not allowed to do."""


class DuplicateError(TeamCollaborationError):
    """Raised when a unique constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime
    description: str = ""


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    created_at: datetime
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    description: str = ""
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    created_at: datetime
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    created_at: datetime
    feedback: str = ""
    task_id: Optional[int] = None


# ---------------------------------------------------------------------------
# Internal stores -- thin containers that share one lock with the manager.
# ---------------------------------------------------------------------------
class _Store:
    def __init__(self, lock):
        self._lock = lock


class _UserStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._items = {}  # id -> User


class _ProjectStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._items = {}  # id -> Project


class _TaskStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._items = {}  # id -> Task
        self._by_project = defaultdict(list)  # project_id -> [task_id]
        self._by_assignee = defaultdict(set)  # assignee_id -> {task_id}


class _MessageStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._items = {}  # id -> Message
        self._by_project = defaultdict(list)  # project_id -> [message_id]
        self._by_task = defaultdict(list)  # task_id -> [message_id]


class _PerformanceStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._ratings = {}  # id -> Rating
        self._by_ratee = defaultdict(list)  # ratee_id -> [Rating]


class _ReportStore(_Store):
    """Stateless; exists for lock-identity and namespacing."""


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _default_now():
    return datetime.now()


def _copy(obj):
    """Return a deep copy so callers can never mutate stored state."""
    return copy.deepcopy(obj)


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory, thread-safe collaboration service.

    A single reentrant lock guards all mutations and is shared by every
    sub-store, which keeps the global id sequence and the secondary indexes
    perfectly consistent under concurrent access.
    """

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._clock = now if now is not None else _default_now
        self._next_id = 1

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal utilities (assume the lock is held) -------------------
    def _allocate_id(self):
        nid = self._next_id
        self._next_id += 1
        return nid

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        msg = self.messages._items.get(message_id)
        if msg is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return msg

    @staticmethod
    def _validate_username(username):
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("email must be a non-empty string with '@'")

    def _username_taken(self, username, exclude_id=None):
        for u in self.users._items.values():
            if u.username == username and u.id != exclude_id:
                return True
        return False

    def _email_taken(self, email, exclude_id=None):
        for u in self.users._items.values():
            if u.email == email and u.id != exclude_id:
                return True
        return False

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            self._validate_username(username)
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if self._username_taken(username):
                raise DuplicateError("username already in use")
            if self._email_taken(email):
                raise DuplicateError("email already in use")
            user = User(
                id=self._allocate_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._clock(),
            )
            self.users._items[user.id] = user
            return _copy(user)

    def get_user(self, user_id):
        with self._lock:
            return _copy(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return [_copy(u) for u in sorted(
                self.users._items.values(), key=lambda u: u.id)]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                self._validate_username(username)
                if self._username_taken(username, exclude_id=user_id):
                    raise DuplicateError("username already in use")
            if email is not None:
                self._validate_email(email)
                if self._email_taken(email, exclude_id=user_id):
                    raise DuplicateError("email already in use")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _copy(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user still owns a project")
            for task_id in self.tasks._by_assignee.get(user_id, set()):
                task = self.tasks._items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an incomplete assigned task")

            del self.users._items[user_id]
            # Completed tasks stay, but drop the now-dangling assignee index.
            self.tasks._by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id,
                       description=""):
        with self._lock:
            self._require_user(owner_id)
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be non-empty")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")
            project = Project(
                id=self._allocate_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._clock(),
                description=description or "",
            )
            self.projects._items[project.id] = project
            return _copy(project)

    def get_project(self, project_id):
        with self._lock:
            return _copy(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return [_copy(p) for p in sorted(
                self.projects._items.values(), key=lambda p: p.id)]

    def update_project(self, project_id, name=None, start_date=None,
                      end_date=None, description=None):
        with self._lock:
            project = self._require_project(project_id)
            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name must be non-empty")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _copy(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            for task_id in list(self.tasks._by_project.get(project_id, [])):
                self._delete_task_internal(task_id)
            for message_id in list(self.messages._by_project.get(project_id, [])):
                self._delete_message_internal(message_id)
            del self.projects._items[project_id]
            self.tasks._by_project.pop(project_id, None)
            self.messages._by_project.pop(project_id, None)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                   description=""):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be non-empty")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")

            task = Task(
                id=self._allocate_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                created_at=self._clock(),
                assignee_id=assignee_id,
                deadline=deadline,
                description=description or "",
            )
            self.tasks._items[task.id] = task
            self.tasks._by_project[project_id].append(task.id)
            if assignee_id is not None:
                self.tasks._by_assignee[assignee_id].add(task.id)
            return _copy(task)

    def get_task(self, task_id):
        with self._lock:
            return _copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            task_ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._items[tid] for tid in task_ids]
            tasks.sort(key=lambda t: t.id)
            return [_copy(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            task_ids = self.tasks._by_assignee.get(assignee_id, set())
            tasks = [self.tasks._items[tid] for tid in task_ids]
            tasks.sort(key=lambda t: t.id)
            return [_copy(t) for t in tasks]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return _copy(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return _copy(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return _copy(task)

    def _set_assignee(self, task, new_assignee_id):
        if task.assignee_id is not None:
            self.tasks._by_assignee.get(task.assignee_id, set()).discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks._by_assignee[new_assignee_id].add(task.id)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline before project start")
            task.deadline = deadline
            return _copy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._clock()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _copy(task)

    def _delete_task_internal(self, task_id):
        task = self.tasks._items.pop(task_id, None)
        if task is None:
            return
        project_list = self.tasks._by_project.get(task.project_id)
        if project_list and task_id in project_list:
            project_list.remove(task_id)
        if task.assignee_id is not None:
            self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
        for message_id in list(self.messages._by_task.get(task_id, [])):
            self._delete_message_internal(message_id)
        self.messages._by_task.pop(task_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                    parent_id=None, attachments=None):
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required")
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = attachments or []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachment_specs:
                raise ValidationError("message needs a body or an attachment")

            now = self._clock()
            built = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._allocate_id(),
                author_id=author_id,
                body=body_text,
                created_at=now,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
            )
            self.messages._items[message.id] = message
            if project_id is not None:
                self.messages._by_project[project_id].append(message.id)
            if task_id is not None:
                self.messages._by_task[task_id].append(message.id)
            return _copy(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            body_text = new_body if isinstance(new_body, str) else ""
            if not body_text.strip() and not message.attachments:
                raise ValidationError("message needs a body or an attachment")
            message.body = body_text
            message.edited_at = self._clock()
            return _copy(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be non-empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._clock(),
                )
            )
            return _copy(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.messages._by_project.get(project_id, [])
            msgs = [self.messages._items[mid] for mid in ids]
            msgs.sort(key=lambda m: m.id)
            return [_copy(m) for m in msgs]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            ids = self.messages._by_task.get(task_id, [])
            msgs = [self.messages._items[mid] for mid in ids]
            msgs.sort(key=lambda m: m.id)
            return [_copy(m) for m in msgs]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete a message")
            self._delete_message_internal(message_id)

    def _delete_message_internal(self, message_id):
        message = self.messages._items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            lst = self.messages._by_project.get(message.project_id)
            if lst and message_id in lst:
                lst.remove(message_id)
        if message.task_id is not None:
            lst = self.messages._by_task.get(message.task_id)
            if lst and message_id in lst:
                lst.remove(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assignee_tasks(self, user_id):
        return [
            self.tasks._items[tid]
            for tid in self.tasks._by_assignee.get(user_id, set())
            if tid in self.tasks._items
        ]

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def _avg_completion_time(self, user_id):
        durations = []
        for task in self._assignee_tasks(user_id):
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds())
        if not durations:
            return None
        return sum(durations) / len(durations)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._avg_completion_time(user_id)

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                     task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int) \
                    or score < 1 or score > 5:
                raise ValidationError("score must be an int in 1..5")
            if task_id is not None:
                self._require_task(task_id)
            rating = Rating(
                id=self._allocate_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                created_at=self._clock(),
                feedback=feedback or "",
                task_id=task_id,
            )
            self.performance._ratings[rating.id] = rating
            self.performance._by_ratee[ratee_id].append(rating)
            return _copy(rating)

    def _ratings_for(self, user_id):
        return self.performance._by_ratee.get(user_id, [])

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [_copy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": self._avg_completion_time(user_id),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def _task_completion_seconds(self, task):
        if (task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            task_ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._items[tid] for tid in task_ids]
            total = len(tasks)

            status_counts = {s.value: 0 for s in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]

            now = self._clock()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "in_progress": 0,
                     "not_started": 0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    bucket["in_progress"] += 1
                else:
                    bucket["not_started"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                task_ids = self.tasks._by_project.get(project_id, [])
                scoped = [self.tasks._items[tid] for tid in task_ids]
            else:
                scoped = list(self.tasks._items.values())

            by_user = defaultdict(list)
            for task in scoped:
                if task.assignee_id is not None:
                    by_user[task.assignee_id].append(task)

            rows = []
            for user_id in sorted(by_user):
                user_tasks = by_user[user_id]
                total = len(user_tasks)
                completed = sum(
                    1 for t in user_tasks
                    if t.status == TaskStatus.COMPLETED)
                durations = [
                    self._task_completion_seconds(t) for t in user_tasks]
                durations = [d for d in durations if d is not None]
                avg = sum(durations) / len(durations) if durations else None
                rows.append({
                    "user_id": user_id,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": completed / total if total else 0.0,
                    "average_completion_time": avg,
                })

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._assignee_tasks(user_id), key=lambda t: t.id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED)
            task_rows = [
                {
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                    "completion_seconds": self._task_completion_seconds(t),
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": self._avg_completion_time(user_id),
                "tasks": task_rows,
            }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, fmt):
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _export_csv(report):
        out = io.StringIO()
        writer = csv.writer(out)
        rows = report.get("rows")
        if isinstance(rows, list):
            if rows:
                columns = list(rows[0].keys())
            else:
                columns = [
                    "user_id", "total_tasks", "completed_tasks",
                    "completion_rate", "average_completion_time",
                ]
            writer.writerow(columns)
            for row in rows:
                writer.writerow([row.get(col, "") for col in columns])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, value])
        return out.getvalue()

    @staticmethod
    def _export_pdf(report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, value))

        content_ops = ["BT", "/F1 11 Tf", "50 750 Td", "14 TL"]
        first = True
        for line in lines:
            safe = (
                str(line)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            if first:
                content_ops.append("({0}) Tj".format(safe))
                first = False
            else:
                content_ops.append("T*")
                content_ops.append("({0}) Tj".format(safe))
        content_ops.append("ET")
        stream = "\n".join(content_ops).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
            b"<< /Length " + str(len(stream)).encode("ascii") + b" >>\n"
            b"stream\n" + stream + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(index).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

        xref_pos = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += ("%010d 00000 n \n" % offset).encode("ascii")
        pdf += b"trailer\n<< /Size " + str(size).encode("ascii")
        pdf += b" /Root 1 0 R >>\n"
        pdf += b"startxref\n" + str(xref_pos).encode("ascii") + b"\n%%EOF"
        return bytes(pdf)
